USE tienda_mysql;

CREATE TABLE IF NOT EXISTS categorias(id_categoria INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(100) NOT NULL UNIQUE,activo BOOLEAN NOT NULL DEFAULT TRUE) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS productos(id_producto INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,id_categoria INT UNSIGNED NOT NULL,nombre VARCHAR(150) NOT NULL,codigo_sku VARCHAR(50) NOT NULL UNIQUE,precio DECIMAL(12,2) NOT NULL,stock INT NOT NULL DEFAULT 0,activo BOOLEAN NOT NULL DEFAULT TRUE,CONSTRAINT chk_producto_precio CHECK(precio>=0),CONSTRAINT chk_producto_stock CHECK(stock>=0),FOREIGN KEY(id_categoria) REFERENCES categorias(id_categoria)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS clientes(id_cliente INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(150) NOT NULL,correo VARCHAR(150) NOT NULL UNIQUE,fecha_registro DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS pedidos(id_pedido INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,id_cliente INT UNSIGNED NOT NULL,fecha_pedido DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,estado ENUM('PENDIENTE','PAGADO','CANCELADO') NOT NULL DEFAULT 'PENDIENTE',FOREIGN KEY(id_cliente) REFERENCES clientes(id_cliente)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS detalle_pedido(id_detalle INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,id_pedido INT UNSIGNED NOT NULL,id_producto INT UNSIGNED NOT NULL,cantidad INT UNSIGNED NOT NULL,precio_unitario DECIMAL(12,2) NOT NULL,CONSTRAINT chk_detalle_cantidad CHECK(cantidad>0),FOREIGN KEY(id_pedido) REFERENCES pedidos(id_pedido) ON DELETE CASCADE,FOREIGN KEY(id_producto) REFERENCES productos(id_producto)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS pagos(id_pago INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,id_pedido INT UNSIGNED NOT NULL,monto DECIMAL(12,2) NOT NULL,metodo VARCHAR(30) NOT NULL,fecha_pago DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(id_pedido) REFERENCES pedidos(id_pedido)) ENGINE=InnoDB;
